  private void setupJavaCompileProperties(Project project) {
    // unlike BaseGeneratorWorker, don't want to pass java compiler settings through JavaCompileFacetInitializer
    //       although still have to do that due to the way JavaCompile facet is written (not the same as in Generate)
    //       In big MPS, it's WorkbenchMakeService that takes responsibility to pass JCOC values into JavaCompile
    //       facet parameters.
    //       Note, perhaps, this approach (when facets use params rather than global services) is reasonable
    //       (except for the fact WorkbenchMakeService shall not know about specific facets)
    //       Anyway, need to make facet approach to parameters consistent (Generate, JavaCompile)
    JavaCompilerProperties jp = new JavaCompilerProperties(myScript);
    // logic comes from WorkerBase
    JavaCompilerOptionsComponent.JavaVersion parsedJavaVersion = JavaCompilerOptionsComponent.JavaVersion.parse(jp.getTargetJavaVersion());
    JavaCompilerOptions options;
    if (parsedJavaVersion == null) {
      options = JavaCompilerOptionsComponent.DEFAULT_JAVA_COMPILER_OPTIONS;
    } else {
      options = new JavaCompilerOptions(parsedJavaVersion);
    }
    JavaCompilerOptionsComponent.getInstance().setJavaCompilerOptions(project, options);
  }

  private void setupGenerationProperties() {
    GeneratorProperties gp = new GeneratorProperties(myScript);
    IModifiableGenerationSettings settings = myEnvironment.getPlatform().findComponent(GenerationSettingsProvider.class).getGenerationSettings();
    boolean strictMode = gp.isStrictMode();
    boolean parallelMode = gp.isParallelMode();
    boolean inplace = gp.isInplaceTransform();
    boolean warnings = !(gp.isHideWarnings());
    int threadCount = gp.getParallelThreads();
    final boolean useStaticRefs = gp.isCreateStaticRefs();
    boolean skipUnmodifiedModels = gp.isSkipUnmodifiedModels();

    settings.setStrictMode(strictMode);
    if (strictMode) {
      settings.setParallelGenerator(parallelMode);
      if (parallelMode) {
        settings.setNumberOfParallelThreads(threadCount);
      }
    }
    String[] onoff = new String[]{"on", "off"};
    settings.enableInplaceTransformations(inplace);
    settings.setShowBadChildWarning(warnings);
    settings.setCreateStaticReferences(useStaticRefs);
    settings.setCheckModelsBeforeGeneration(false);
    if ("info".equalsIgnoreCase(gp.getMessageLevel())) {
      settings.setShowInfo(true);
      settings.setShowWarnings(true);
    }
    if ("warn".equalsIgnoreCase(gp.getMessageLevel())) {
      settings.setShowWarnings(true);
    }
    info(String.format("Generating: strict mode is %s, parallel generation is %s (%d threads), in-place is %s, child warnings are %s, static references to replace dynamic is %s, skip unmodified models is %s", onoff[(strictMode ? 0 : 1)], onoff[(parallelMode ? 0 : 1)], (parallelMode ? threadCount : 1), onoff[(inplace ? 0 : 1)], onoff[(warnings ? 0 : 1)], onoff[(useStaticRefs ? 0 : 1)], onoff[(skipUnmodifiedModels ? 0 : 1)]));
  }

  private void info(String m) {
    myMessageHandler.handle(Message.info(MakeExecutor.class, m, null, null));
  }
